import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import { providerAPI } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

const CATEGORIES = {
  Electrician: ['Wiring', 'Fan Repair', 'Switchboard Fixing', 'AC Installation', 'MCB Repair', 'CCTV Installation'],
  Plumber: ['Pipe Repair', 'Tap Fixing', 'Bathroom Fitting', 'Water Tank Cleaning', 'Drain Cleaning'],
  Carpenter: ['Furniture Repair', 'Door Fitting', 'Cupboard Making', 'Wood Polishing'],
  Painter: ['Wall Painting', 'Waterproofing', 'Texture Painting', 'Exterior Painting'],
  Cleaner: ['Home Cleaning', 'Office Cleaning', 'Sofa Cleaning', 'Deep Cleaning'],
  ACTechnician: ['AC Installation', 'AC Service', 'AC Gas Refill', 'AC Repair'],
};

const STEPS = ['Category & Skills', 'Location & Pricing', 'Availability & Bio'];

export default function ProviderOnboarding() {
  const { fetchMe } = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    serviceCategory: '',
    skills: [],
    experience: 1,
    priceMin: 200,
    priceMax: 1000,
    address: '',
    lat: '',
    lng: '',
    bio: '',
    workingHoursStart: '08:00',
    workingHoursEnd: '20:00',
    workingDays: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'],
  });

  const toggleSkill = (skill) => {
    setForm(f => ({
      ...f,
      skills: f.skills.includes(skill) ? f.skills.filter(s => s !== skill) : [...f.skills, skill],
    }));
  };

  const toggleDay = (day) => {
    setForm(f => ({
      ...f,
      workingDays: f.workingDays.includes(day) ? f.workingDays.filter(d => d !== day) : [...f.workingDays, day],
    }));
  };

  const getLocation = () => {
    navigator.geolocation?.getCurrentPosition(
      ({ coords }) => {
        setForm(f => ({ ...f, lat: coords.latitude, lng: coords.longitude }));
        toast.success('Location detected!');
      },
      () => toast.error('Could not get location')
    );
  };

  const handleSubmit = async () => {
    if (!form.serviceCategory) return toast.error('Select a category');
    if (form.skills.length === 0) return toast.error('Select at least one skill');
    if (!form.address) return toast.error('Enter your service location');
    if (!form.lat || !form.lng) return toast.error('Detect your location first');

    setLoading(true);
    try {
      await providerAPI.createProfile({
        serviceCategory: form.serviceCategory,
        skills: form.skills,
        experience: Number(form.experience),
        priceRange: { min: Number(form.priceMin), max: Number(form.priceMax) },
        location: { address: form.address, lat: Number(form.lat), lng: Number(form.lng) },
        bio: form.bio,
        availability: {
          isAvailable: true,
          workingHours: { start: form.workingHoursStart, end: form.workingHoursEnd },
          workingDays: form.workingDays,
        },
      });
      await fetchMe();
      toast.success('Profile created! Pending admin approval.');
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to create profile');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div className="page-container" style={{ paddingTop: 40, paddingBottom: 60, maxWidth: 640 }}>
        <div style={{ marginBottom: 32 }}>
          <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 6 }}>Set Up Your Provider Profile</h1>
          <p style={{ color: 'var(--text-secondary)', fontSize: 14 }}>Complete this to start receiving bookings</p>

          {/* Step Indicator */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 24 }}>
            {STEPS.map((s, i) => (
              <React.Fragment key={s}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                  <div style={{
                    width: 28, height: 28, borderRadius: '50%', border: `2px solid ${i <= step ? 'var(--accent)' : 'var(--border)'}`,
                    background: i < step ? 'var(--accent)' : 'transparent',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 12, fontWeight: 700, color: i < step ? '#fff' : i === step ? 'var(--accent)' : 'var(--text-muted)',
                  }}>{i < step ? '✓' : i + 1}</div>
                  <span style={{ fontSize: 12, color: i === step ? 'var(--text-primary)' : 'var(--text-muted)', display: 'none', ['@media (min-width: 480px)']: { display: 'block' } }}>
                    {s}
                  </span>
                </div>
                {i < STEPS.length - 1 && <div style={{ flex: 1, height: 2, background: i < step ? 'var(--accent)' : 'var(--border)' }} />}
              </React.Fragment>
            ))}
          </div>
        </div>

        <div className="card">
          {/* Step 0: Category & Skills */}
          {step === 0 && (
            <div className="animate-fade">
              <h3 style={{ fontWeight: 700, marginBottom: 20, fontSize: 16 }}>What service do you provide?</h3>

              <div className="form-group" style={{ marginBottom: 20 }}>
                <label className="form-label">Service Category *</label>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 8 }}>
                  {Object.keys(CATEGORIES).map(cat => (
                    <button key={cat} type="button"
                      className={`btn btn-sm ${form.serviceCategory === cat ? 'btn-primary' : 'btn-ghost'}`}
                      style={{ flexDirection: 'column', padding: '10px 8px', height: 'auto' }}
                      onClick={() => setForm(f => ({ ...f, serviceCategory: cat, skills: [] }))}>
                      <span style={{ fontSize: 20 }}>{{ Electrician: '⚡', Plumber: '🔧', Carpenter: '🪚', Painter: '🎨', Cleaner: '🧹', ACTechnician: '❄️' }[cat]}</span>
                      <span style={{ fontSize: 11, marginTop: 4 }}>{cat}</span>
                    </button>
                  ))}
                </div>
              </div>

              {form.serviceCategory && (
                <div className="form-group" style={{ marginBottom: 20 }}>
                  <label className="form-label">Skills / Sub-services * (select all that apply)</label>
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                    {CATEGORIES[form.serviceCategory].map(skill => (
                      <button key={skill} type="button"
                        className={`btn btn-sm ${form.skills.includes(skill) ? 'btn-primary' : 'btn-ghost'}`}
                        onClick={() => toggleSkill(skill)}>{skill}</button>
                    ))}
                  </div>
                </div>
              )}

              <div className="form-group">
                <label className="form-label">Years of Experience *</label>
                <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                  <input type="range" min="0" max="30" value={form.experience}
                    onChange={e => setForm(f => ({ ...f, experience: e.target.value }))}
                    style={{ flex: 1, accentColor: 'var(--accent)' }} />
                  <span style={{ fontWeight: 700, fontSize: 18, fontFamily: 'var(--font-display)', color: 'var(--accent)', minWidth: 40, textAlign: 'center' }}>
                    {form.experience}y
                  </span>
                </div>
              </div>
            </div>
          )}

          {/* Step 1: Location & Pricing */}
          {step === 1 && (
            <div className="animate-fade">
              <h3 style={{ fontWeight: 700, marginBottom: 20, fontSize: 16 }}>Location & Pricing</h3>

              <div className="form-group" style={{ marginBottom: 16 }}>
                <label className="form-label">Service Location / Address *</label>
                <textarea className="form-textarea" style={{ minHeight: 70 }}
                  placeholder="e.g. Anna Nagar, Chennai, Tamil Nadu"
                  value={form.address} onChange={e => setForm(f => ({ ...f, address: e.target.value }))} />
              </div>

              <button className="btn btn-secondary btn-sm" style={{ marginBottom: 20 }} onClick={getLocation}>
                📍 Auto-detect My Location
              </button>
              {form.lat && form.lng && (
                <p style={{ fontSize: 12, color: 'var(--success)', marginBottom: 16 }}>
                  ✓ GPS: {Number(form.lat).toFixed(4)}, {Number(form.lng).toFixed(4)}
                </p>
              )}

              <div style={{ marginBottom: 20 }}>
                <label className="form-label" style={{ display: 'block', marginBottom: 10 }}>Price Range (₹) *</label>
                <div className="grid-2">
                  <div className="form-group">
                    <label className="form-label">Minimum</label>
                    <input className="form-input" type="number" placeholder="200" value={form.priceMin}
                      onChange={e => setForm(f => ({ ...f, priceMin: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Maximum</label>
                    <input className="form-input" type="number" placeholder="1000" value={form.priceMax}
                      onChange={e => setForm(f => ({ ...f, priceMax: e.target.value }))} />
                  </div>
                </div>
                <p style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 8 }}>This is your indicative price range. You can negotiate the final price with each customer.</p>
              </div>
            </div>
          )}

          {/* Step 2: Availability & Bio */}
          {step === 2 && (
            <div className="animate-fade">
              <h3 style={{ fontWeight: 700, marginBottom: 20, fontSize: 16 }}>Availability & About You</h3>

              <div className="form-group" style={{ marginBottom: 16 }}>
                <label className="form-label">Working Days *</label>
                <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                  {['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'].map(d => (
                    <button key={d} type="button"
                      className={`btn btn-sm ${form.workingDays.includes(d) ? 'btn-primary' : 'btn-ghost'}`}
                      onClick={() => toggleDay(d)}>{d}</button>
                  ))}
                </div>
              </div>

              <div className="grid-2" style={{ marginBottom: 16 }}>
                <div className="form-group">
                  <label className="form-label">Work Start Time</label>
                  <input className="form-input" type="time" value={form.workingHoursStart}
                    onChange={e => setForm(f => ({ ...f, workingHoursStart: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label className="form-label">Work End Time</label>
                  <input className="form-input" type="time" value={form.workingHoursEnd}
                    onChange={e => setForm(f => ({ ...f, workingHoursEnd: e.target.value }))} />
                </div>
              </div>

              <div className="form-group">
                <label className="form-label">About You (Bio)</label>
                <textarea className="form-textarea"
                  placeholder="Tell customers about your experience, specializations, and why they should choose you..."
                  value={form.bio} onChange={e => setForm(f => ({ ...f, bio: e.target.value }))} />
                <span style={{ fontSize: 11, color: 'var(--text-muted)' }}>{form.bio.length}/500</span>
              </div>
            </div>
          )}

          {/* Navigation */}
          <div style={{ display: 'flex', gap: 10, marginTop: 28, justifyContent: 'space-between' }}>
            {step > 0 ? (
              <button className="btn btn-ghost" onClick={() => setStep(s => s - 1)}>← Back</button>
            ) : <div />}
            {step < STEPS.length - 1 ? (
              <button className="btn btn-primary" onClick={() => setStep(s => s + 1)}>Next →</button>
            ) : (
              <button className="btn btn-primary" onClick={handleSubmit} disabled={loading} style={{ minWidth: 140 }}>
                {loading ? 'Creating...' : '🚀 Create Profile'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
